#!/usr/bin/env python3
from __future__ import annotations

from pathlib import Path


FILES = {
    "asca_ad/trainer.py": 'from __future__ import annotations\n\nimport importlib.util\nimport sys\nimport time\nfrom pathlib import Path\nfrom typing import Any\n\nimport torch\n\nfrom .config import PROJECT_ROOT, load_dataset_config, load_experiment_config, select_datasets\n\n\ndef _import_module_from_path(path: Path, name: str):\n    if not path.exists():\n        raise FileNotFoundError(f"Missing runner file: {path}")\n\n    spec = importlib.util.spec_from_file_location(name, str(path))\n    if spec is None or spec.loader is None:\n        raise RuntimeError(f"Cannot import runner: {path}")\n\n    module = importlib.util.module_from_spec(spec)\n    sys.modules[name] = module\n    spec.loader.exec_module(module)\n    return module\n\n\ndef _runner_path(runner_file: str) -> Path:\n    path = PROJECT_ROOT / "scripts" / "dataset_runners" / runner_file\n    if not path.exists():\n        raise FileNotFoundError(f"Missing dataset runner: {path}")\n    return path\n\n\ndef train_one_dataset(\n    dataset: str,\n    seed: int | None = None,\n    epochs: int | None = None,\n    force: bool = False,\n) -> dict[str, Any]:\n    """Train one dataset through the currently validated dataset runner.\n\n    By default, existing checkpoints are reused. Use force=True only when you\n    intentionally want to retrain and overwrite the current checkpoint.\n    """\n    dataset_config = load_dataset_config()\n    experiment_config = load_experiment_config()\n\n    key = dataset.strip().upper()\n    if key not in dataset_config:\n        valid = ", ".join(dataset_config.keys())\n        raise ValueError(f"Unknown dataset: {key}. Valid datasets: {valid}")\n\n    cfg = dataset_config[key]\n    final_seed = int(seed) if seed is not None else int(experiment_config.get("default_seed", 42))\n    final_epochs = int(epochs) if epochs is not None else int(cfg.get("epochs", 3))\n\n    runner_file = str(cfg["runner"])\n    runner_path = _runner_path(runner_file)\n    module = _import_module_from_path(runner_path, f"asca_ad_train_runner_{key.lower()}")\n\n    if hasattr(module, "set_seed"):\n        module.set_seed(final_seed)\n\n    print()\n    print("=" * 80)\n    print(f"[{key}] Training")\n    print("=" * 80)\n    print(f"[{key}] runner : {runner_path}")\n    print(f"[{key}] seed   : {final_seed}")\n    print(f"[{key}] epochs : {final_epochs}")\n\n    channels = module.verify_data(PROJECT_ROOT)\n    _OriginalSolver, V4Solver = module.bootstrap_project(PROJECT_ROOT)\n    config = module.v4_config(PROJECT_ROOT, channels, final_seed, final_epochs)\n\n    runner = V4Solver(config)\n    checkpoint = Path(runner.checkpoint_path)\n\n    if checkpoint.exists() and not force:\n        print(f"[{key}] checkpoint exists; skip training: {checkpoint}")\n        return {\n            "dataset": key,\n            "trained": False,\n            "skipped": True,\n            "reason": "checkpoint_exists",\n            "checkpoint": str(checkpoint),\n            "runner": str(runner_path),\n            "epochs": final_epochs,\n            "seed": final_seed,\n        }\n\n    start = time.perf_counter()\n    runner.train()\n\n    if torch.cuda.is_available():\n        torch.cuda.synchronize()\n\n    seconds = time.perf_counter() - start\n    print(f"[{key}] training seconds: {seconds:.3f}")\n    print(f"[{key}] checkpoint      : {checkpoint}")\n\n    return {\n        "dataset": key,\n        "trained": True,\n        "skipped": False,\n        "checkpoint": str(checkpoint),\n        "runner": str(runner_path),\n        "epochs": final_epochs,\n        "seed": final_seed,\n        "training_seconds": float(seconds),\n    }\n\n\ndef train_datasets(\n    dataset: str,\n    seed: int | None = None,\n    epochs: int | None = None,\n    force: bool = False,\n) -> list[dict[str, Any]]:\n    dataset_config = load_dataset_config()\n    datasets = select_datasets(dataset, dataset_config)\n\n    results: list[dict[str, Any]] = []\n    for item in datasets:\n        results.append(\n            train_one_dataset(\n                dataset=item,\n                seed=seed,\n                epochs=epochs,\n                force=force,\n            )\n        )\n    return results\n',
    "asca_ad/pipeline.py": 'from __future__ import annotations\n\nimport json\nfrom pathlib import Path\nfrom typing import Any\n\nfrom .config import PROJECT_ROOT\nfrom .evaluator import run_evaluation\nfrom .trainer import train_datasets\n\n\nVALID_MODES = {"eval", "train", "train-eval"}\n\n\ndef run_pipeline(\n    dataset: str,\n    mode: str = "train-eval",\n    output_dir: str | None = None,\n    seed: int | None = None,\n    epochs: int | None = None,\n    train_if_missing: bool = True,\n    force_train: bool = False,\n) -> dict[str, Any]:\n    """Run ASCA-AD from a single entrypoint.\n\n    Modes:\n    - eval: evaluate existing checkpoint only.\n    - train: train missing checkpoints; use --force-train to retrain existing ones.\n    - train-eval: train missing checkpoints, then evaluate.\n    """\n    mode = mode.strip().lower()\n    if mode not in VALID_MODES:\n        valid = ", ".join(sorted(VALID_MODES))\n        raise ValueError(f"Unknown mode: {mode}. Valid modes: {valid}")\n\n    train_results: list[dict[str, Any]] = []\n    eval_results: list[dict[str, Any]] = []\n\n    if mode in {"train", "train-eval"}:\n        train_results = train_datasets(\n            dataset=dataset,\n            seed=seed,\n            epochs=epochs,\n            force=force_train,\n        )\n\n    if mode in {"eval", "train-eval"}:\n        eval_results = run_evaluation(\n            dataset=dataset,\n            output_dir=output_dir,\n            seed=seed,\n            epochs=epochs,\n            train_if_missing=train_if_missing,\n        )\n\n    summary = {\n        "dataset": dataset,\n        "mode": mode,\n        "force_train": bool(force_train),\n        "train_results": train_results,\n        "eval_results": eval_results,\n    }\n\n    pipeline_dir = PROJECT_ROOT / "results" / "PIPELINE_RUNS"\n    pipeline_dir.mkdir(parents=True, exist_ok=True)\n    safe_name = dataset.strip().upper().replace(",", "_")\n    summary_path = pipeline_dir / f"{safe_name}_{mode}.json"\n    summary_path.write_text(\n        json.dumps(summary, ensure_ascii=False, indent=2),\n        encoding="utf-8",\n    )\n\n    print()\n    print("Pipeline summary:")\n    print(summary_path)\n\n    return summary\n',
    "scripts/run.py": '#!/usr/bin/env python3\nfrom __future__ import annotations\n\nimport argparse\nimport sys\nfrom pathlib import Path\n\nPROJECT_ROOT = Path(__file__).resolve().parents[1]\nif str(PROJECT_ROOT) not in sys.path:\n    sys.path.insert(0, str(PROJECT_ROOT))\n\nfrom asca_ad.pipeline import run_pipeline\n\n\ndef main() -> None:\n    parser = argparse.ArgumentParser(\n        description="Run ASCA-AD training and evaluation from one script."\n    )\n    parser.add_argument(\n        "dataset",\n        help="Dataset name: SKAB, PUMP, PSM, MSL, SMAP, HAI, SMD, WADI, or all.",\n    )\n    parser.add_argument(\n        "--mode",\n        choices=["eval", "train", "train-eval"],\n        default="train-eval",\n        help="Default: train-eval. Existing checkpoints are reused unless --force-train is set.",\n    )\n    parser.add_argument("--output-dir", default=None)\n    parser.add_argument("--seed", type=int, default=None)\n    parser.add_argument("--epochs", type=int, default=None)\n    parser.add_argument(\n        "--force-train",\n        action="store_true",\n        help="Retrain even when a checkpoint already exists.",\n    )\n    parser.add_argument(\n        "--no-train-if-missing",\n        action="store_true",\n        help="In eval/train-eval mode, fail instead of training when checkpoint is missing.",\n    )\n    args = parser.parse_args()\n\n    run_pipeline(\n        dataset=args.dataset,\n        mode=args.mode,\n        output_dir=args.output_dir,\n        seed=args.seed,\n        epochs=args.epochs,\n        train_if_missing=not args.no_train_if_missing,\n        force_train=args.force_train,\n    )\n\n\nif __name__ == "__main__":\n    main()\n',
    "asca_ad/__init__.py": '"""ASCA-AD package."""\n\nfrom .evaluator import run_evaluation\nfrom .pipeline import run_pipeline\nfrom .trainer import train_datasets, train_one_dataset\n\n__all__ = [\n    "run_evaluation",\n    "run_pipeline",\n    "train_datasets",\n    "train_one_dataset",\n]\n',
    "docs/stage4_train_eval_pipeline.md": '# Stage 4: single-script train and evaluate pipeline\n\n## Main command\n\nRun one dataset:\n\n    python scripts/run.py SKAB\n\nRun evaluation only:\n\n    python scripts/run.py SKAB --mode eval\n\nTrain missing checkpoint and then evaluate:\n\n    python scripts/run.py SKAB --mode train-eval\n\nForce retraining and then evaluate:\n\n    python scripts/run.py SKAB --mode train-eval --force-train\n\nRun multiple datasets:\n\n    python scripts/run.py SKAB,PUMP,PSM --mode eval\n\nRun all datasets:\n\n    python scripts/run.py all --mode eval\n\n## Code structure\n\nThe command-line layer is thin:\n\n    scripts/run.py\n\nThe pipeline logic is in:\n\n    asca_ad/pipeline.py\n\nTraining logic is in:\n\n    asca_ad/trainer.py\n\nEvaluation logic is in:\n\n    asca_ad/evaluator.py\n\nDataset and experiment configuration is in:\n\n    configs/datasets.json\n    configs/experiment.json\n\nModel architecture remains in:\n\n    asca_ad/model.py\n\nThis stage does not change the ASCA-AD model algorithm. It only improves the\nproject structure and provides a single entrypoint for training and evaluation.\n',
    "scripts/README.md": '# Scripts\n\nRecommended entrypoint:\n\n    python scripts/run.py SKAB\n\nDefault behavior:\n\n    train missing checkpoint, then evaluate\n\nCommon commands:\n\n    python scripts/run.py SKAB\n    python scripts/run.py SKAB --mode eval\n    python scripts/run.py SKAB --mode train-eval --force-train\n    python scripts/run.py SKAB,PUMP,PSM --mode eval\n    python scripts/run.py all --mode eval\n\nEvaluation-only compatibility entrypoint:\n\n    python scripts/evaluate.py SKAB\n\nShort shell wrappers:\n\n    bash scripts/eval.sh SKAB\n    bash scripts/eval_all.sh\n\nOutputs:\n\n    results/FIXED_COMBINED/<DATASET>/\n    results/PIPELINE_RUNS/\n',
}


def write(path: Path, text: str, executable: bool = False) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")
    if executable:
        path.chmod(0o755)


def main() -> None:
    root = Path.cwd()

    required = [
        root / "asca_ad" / "evaluator.py",
        root / "asca_ad" / "config.py",
        root / "scripts" / "run_all_fixed_combined.py",
        root / "scripts" / "dataset_runners",
        root / "configs" / "datasets.json",
        root / "configs" / "experiment.json",
    ]
    missing = [str(p) for p in required if not p.exists()]
    if missing:
        raise FileNotFoundError("Missing required files/directories:\n" + "\n".join(missing))

    for rel, content in FILES.items():
        write(root / rel, content, executable=(rel == "scripts/run.py"))

    print("Stage 4 files created.")
    print("Next tests:")
    print("  python -m py_compile scripts/run.py asca_ad/trainer.py asca_ad/pipeline.py")
    print("  python -u scripts/run.py SKAB --mode eval")
    print("  python -u scripts/run.py PUMP --mode eval")


if __name__ == "__main__":
    main()
